    "className": "language-python"
  }), "# -*- coding:utf-8 -*-\n# class RandomListNode:\n#     def __init__(self, x):\n#         self.label = x\n#         self.next = None\n#         self.random = None\nclass Solution:\n    # \u8FD4\u56DE RandomListNode\n    def Clone(self, pHead):\n        # \u6309\u7167\u601D\u8DEF2\u6765\u5199\u7684\n        if not pHead:\n            return None\n        nHead = RandomListNode(pHead.label)\n        pCurrent = pHead.next\n        nCurrent = nHead\n        # \u521D\u59CB\u5316\u6620\u5C04\n        mapper = {}\n        # \u9700\u8981\u6CE8\u610F\uFF0C\u8981\u7279\u522B\u6DFB\u52A0\u4E00\u4E2ANone\u5230None\u7684\u6620\u5C04\uFF01\uFF01\n        mapper[id(pHead)] = nHead\n        mapper[id(None)] = None\n        # \u539F\u6837\u590D\u5236\u94FE\u8868\n        while(pCurrent):\n            node = RandomListNode(pCurrent.label)\n            nCurrent.next = node\n            nCurrent = node\n            mapper[id(pCurrent)] = node\n            pCurrent = pCurrent.next\n        # \u6DFB\u52A0random\u6307\u9488\n        pCurrent = pHead\n        nCurrent = nHead\n        while(pCurrent):\n            nCurrent.random = mapper[id(pCurrent.random)]\n            pCurrent = pCurrent.next\n            nCurrent = nCurrent.next\n        return nHead\n")), mdx("h2", {
